<?php
namespace app\Services; use app\Repositories\BookTypeRepository; use app\Requests\Validator;
class BookTypeService{ private BookTypeRepository $repo; public function __construct(){ $this->repo=new BookTypeRepository(); } public function all($q=''){return $this->repo->all($q);} public function find($id){return $this->repo->find((int)$id);} public function save(array $d,?int $id=null):array{ $e=Validator::required($d,['name'=>'Tên loại sách']); if($e)return ['ok'=>false,'errors'=>$e]; $id?$this->repo->update($id,$d):$id=$this->repo->create($d); return ['ok'=>true,'data'=>$this->repo->find($id)]; } public function delete(int $id):array{ if($this->repo->countBooks($id)>0)return ['ok'=>false,'message'=>'Không thể xóa vì đang có sách thuộc loại này']; $this->repo->delete($id); return ['ok'=>true]; }}
